module up_counter_32bit(
    input clk,           // Clock signal.
    input rst,           // Asynchronous reset signal.
    input en,            // Enable signal to increment the counter.

    output [31:0] count  // 32-bit counter output.
);

reg [31:0] unused_count_r; // Counter register.

// Data bit control
always @(posedge clk or posedge rst)
    if (rst) unused_count_r <= 32'b0; // Reset condition
    else if (en) unused_count_r <= unused_count_r + 1; // Increment when enabled

assign count = unused_count_r;

endmodule
